effect.shader:
vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

const highp mat3 rgb2yuv = mat3(
     0.299,     0.587,    0.114,
    -0.14713,  -0.28886,  0.436,
     0.615,    -0.51499, -0.10001
);

const highp mat3 yuv2rgb = mat3(
    1.0,  0.0,      1.13983,
    1.0, -0.39465, -0.58060,
    1.0,  2.03211,  0.0
);

void main() {

    vec4 source = texture2DCv(inputImg.texture,acScreenNorm);
    float luminance = dot(source.rgb, luminanceWeighting);

    float gamma = tint.z+1.0;
    luminance = pow(luminance,1.0/gamma);

    float hue = tint.x /360.;
    //float seg = (tint.x+360.) /60.;
    float sat = tint.y;

    float lowHue = hue - mod(hue, 1./6. );
    float highHue = lowHue + 1./6.;

    vec3 lowColor = hsv2rgb(vec3(lowHue,sat,1.0));
    vec3 baseColor = hsv2rgb(vec3(hue,sat,1.0));
    vec3 highColor = hsv2rgb(vec3(highHue,sat,1.0));

    vec3 darkColor;
    vec3 lightColor;
    if( abs(hue-lowHue) > abs(hue-highHue) ) {
        lightColor = highColor;
        darkColor = lowColor;
    } else {
        lightColor = lowColor;
        darkColor = highColor;
    }

    vec3 blendColor = luminance < 0.5 ? mix( darkColor, baseColor, luminance*2.) :  mix( baseColor, lightColor, (luminance-0.5)*2.);

    vec3 yuv = blendColor * rgb2yuv;
    yuv.x = luminance;
    yuv.yz *= luminance;
    blendColor = yuv * yuv2rgb;

    float shineStart = .85;
    float shineAmount = max(0.,luminance - shineStart) * (1./(1.-shineStart));
    shineAmount = shineAmount * shineAmount * sat;
    blendColor = mix( blendColor, vec3(1.), shineAmount );

    //vec3 darkColor = hsv2rgb(vec3(fract(hue+.95),sat,1.0)) * rgb2yuv;
    //vec3 baseColor = hsv2rgb(vec3(hue,sat,1.0)) * rgb2yuv;
    //vec3 brightColor = hsv2rgb(vec3(fract(hue+.05),sat,1.)) * rgb2yuv;
    //
    //vec3 outColor;
    //if( luminance < 0.25 ) {
    //    outColor = mix(vec3(0.),darkColor,(luminance*4.));
    //} else if( luminance < 0.5 ) {
    //    outColor = mix(darkColor,baseColor,((luminance-0.25)*4.));
    //} else if( luminance < 0.75 ) {
    //    outColor = mix(baseColor,brightColor,((luminance-0.5)*4.));
    //} else {
    //    outColor = brightColor; // mix(brightColor,vec3(1.,0.0,0.0),((luminance-0.75)*4.));
    //}
    //
    //outColor.x = luminance;
    //
    //vec3 rgb = outColor * yuv2rgb;
    //
    //if( luminance >= 0.75 ) {
    //    rgb = mix(rgb,vec3(1.),((luminance-0.75)*4.));
    //}
    gl_FragColor = vec4(blendColor,1.0) * source.a;
}
